import React from 'react';
import { Outlet, NavLink, useNavigate } from 'react-router-dom';

export default function Layout() {
  const navigate = useNavigate();
  return (
    <div style={s.app}>
      <header style={s.header}>
        <div style={s.logo} onClick={() => navigate('/')} role="button">
          <span style={s.logoIcon}>🚛</span>
          <div>
            <div style={s.logoText}>Maruti Trucks</div>
            <div style={s.logoSub}>Birgunj Transport Co.</div>
          </div>
        </div>
        <nav style={s.nav}>
          {navLinks.map(l => (
            <NavLink
              key={l.to}
              to={l.to}
              style={({ isActive }) => ({ ...s.navBtn, ...(isActive ? s.navActive : {}) })}
            >
              {l.label}
            </NavLink>
          ))}
        </nav>
      </header>
      <main style={s.main}>
        <Outlet />
      </main>
    </div>
  );
}

const navLinks = [
  { to: '/',            label: '🏠 Home' },
  { to: '/trucks',      label: '🚛 Trucks' },
  { to: '/scrap',       label: '♻️ Scrap' },
  { to: '/diesel',      label: '⛽ Diesel' },
  { to: '/dashboard',   label: '📊 Dashboard' },
  { to: '/drivers',     label: '👤 Drivers' },
  { to: '/maintenance', label: '🔧 Maintenance' },
  { to: '/customers',   label: '🤝 Customers' },
];

const s = {
  app:       { minHeight: '100vh', background: '#f0f4f8', fontFamily: "'Segoe UI', sans-serif" },
  header:    { background: '#1a3a5c', color: '#fff', padding: '0 24px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', height: 60, boxShadow: '0 2px 8px rgba(0,0,0,0.2)', flexWrap: 'wrap', gap: 8 },
  logo:      { display: 'flex', alignItems: 'center', gap: 12, cursor: 'pointer' },
  logoIcon:  { fontSize: 26 },
  logoText:  { fontSize: 17, fontWeight: 700 },
  logoSub:   { fontSize: 11, opacity: 0.7, marginTop: 1 },
  nav:       { display: 'flex', gap: 4, flexWrap: 'wrap' },
  navBtn:    { padding: '6px 11px', border: '1px solid rgba(255,255,255,0.25)', borderRadius: 6, background: 'transparent', color: '#fff', cursor: 'pointer', fontSize: 12, fontWeight: 500, textDecoration: 'none' },
  navActive: { background: 'rgba(255,255,255,0.2)', border: '1px solid #fff', fontWeight: 700 },
  main:      { maxWidth: 1300, margin: '0 auto', padding: '24px 16px' },
};
